import { Link } from 'react-router-dom'
import { Download, FileText, Package } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Product } from '@/data/products'
import { useToast } from '@/hooks/use-toast'
import useUserStore from '@/stores/useUserStore'

interface ProfileLibraryProps {
  libraryProducts: Product[]
}

export default function ProfileLibrary({ libraryProducts }: ProfileLibraryProps) {
  const { toast } = useToast()
  const { downloadCounts, incrementDownload } = useUserStore()

  const handleDownload = (productId: string, fileType: string) => {
    const currentDownloads = downloadCounts[productId] || 0
    if (currentDownloads >= 3) {
      toast({
        title: 'Limite atingido',
        description:
          'Limite de downloads atingido (3/3). Compre novamente para reativar o acesso de download.',
        variant: 'destructive',
      })
      return
    }

    incrementDownload(productId)
    toast({
      title: 'Download iniciado',
      description: `Baixando: ${fileType}. (${currentDownloads + 1}/3 downloads)`,
    })
  }

  if (libraryProducts.length === 0) {
    return (
      <div className="text-center py-16 bg-muted/30 rounded-2xl border border-dashed">
        <Package className="w-12 h-12 text-muted-foreground/30 mx-auto mb-4" />
        <h3 className="text-xl font-medium mb-2">Nenhum modelo adquirido</h3>
        <p className="text-muted-foreground mb-6">Você ainda não tem arquivos na sua biblioteca.</p>
        <Button asChild>
          <Link to="/">Explorar Catálogo</Link>
        </Button>
      </div>
    )
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {libraryProducts.map((product, idx) => {
        const downloads = downloadCounts[product.id] || 0
        const isLimitReached = downloads >= 3

        return (
          <Card
            key={`${product.id}-${idx}`}
            className="overflow-hidden flex flex-col group border-border/50 shadow-subtle hover:shadow-md transition-all relative"
          >
            <div className="aspect-video relative bg-muted overflow-hidden">
              <img
                src={product.images[0]}
                alt={product.title}
                className={`w-full h-full object-cover transition-transform duration-500 ${isLimitReached ? 'opacity-50 grayscale' : 'group-hover:scale-105'}`}
              />
              {idx === 0 && !isLimitReached && (
                <Badge className="absolute top-3 left-3 bg-primary text-primary-foreground font-bold shadow-sm border-none uppercase tracking-wider text-[10px]">
                  Novo Arquivo
                </Badge>
              )}
            </div>
            <CardContent className="p-5 flex-1 flex flex-col">
              <h3 className="font-semibold text-lg line-clamp-1 mb-2 group-hover:text-primary transition-colors">
                {product.title}
              </h3>
              <p className="text-sm text-muted-foreground mb-6">
                Arquivos prontos para impressão e corte.
              </p>
              <div className="flex flex-col gap-2 mt-auto">
                <Button
                  size="sm"
                  className="w-full gap-2"
                  disabled={isLimitReached}
                  onClick={() => handleDownload(product.id, `${product.title} - Moldes PDF`)}
                >
                  <Download className="w-4 h-4" /> Baixar Moldes ({downloads}/3)
                </Button>
                <Button
                  size="sm"
                  variant="outline"
                  className="w-full gap-2"
                  disabled={isLimitReached}
                  onClick={() => handleDownload(product.id, `${product.title} - Instruções`)}
                >
                  <FileText className="w-4 h-4" /> Ver Instruções ({downloads}/3)
                </Button>
                {isLimitReached && (
                  <p className="text-[10px] text-destructive text-center mt-1 font-medium">
                    Limite de downloads atingido (3/3).
                  </p>
                )}
              </div>
            </CardContent>
          </Card>
        )
      })}
    </div>
  )
}
