export interface Product {
  id: string
  title: string
  price: number
  categoryId: string
  category: string
  difficulty: number // 1 to 5
  images: string[]
  video?: string
  description: string
  specs: {
    sheets: number | string
    time: string
    dimensions: string
  }
  rating: number
  isNew?: boolean
  isBestSeller?: boolean
  tags: string[]
}

export interface Category {
  id: string
  name: string
}

// Export empty arrays to maintain type resolution and avoid breaking backwards compatibility
// with arbitrary imports across the application. The actual source of truth is now the DB.
export const categories: string[] = []
export const products: Product[] = []
