import { useState } from 'react'
import { LogOut, Heart } from 'lucide-react'
import { Link } from 'react-router-dom'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { useToast } from '@/hooks/use-toast'
import useUserStore, { type User } from '@/stores/useUserStore'
import useWishlistStore from '@/stores/useWishlistStore'

export default function ProfileSettings() {
  const { user, updateUser } = useUserStore()
  const { items: wishlistItems } = useWishlistStore()
  const { toast } = useToast()

  const [formData, setFormData] = useState<User>({ name: user.name, email: user.email })
  const [isSaving, setIsSaving] = useState(false)

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault()
    setIsSaving(true)
    setTimeout(() => {
      updateUser(formData)
      setIsSaving(false)
      toast({
        title: 'Perfil atualizado',
        description: 'Suas informações foram salvas com sucesso.',
      })
    }, 800)
  }

  return (
    <div className="grid md:grid-cols-2 gap-8">
      <Card className="border-border/50 shadow-subtle">
        <CardHeader>
          <CardTitle>Detalhes da Conta</CardTitle>
          <CardDescription>Atualize suas informações pessoais.</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSave} className="space-y-5">
            <div className="space-y-2">
              <Label htmlFor="name">Nome Completo</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                required
                className="h-11"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">Endereço de E-mail</Label>
              <Input
                id="email"
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                required
                className="h-11"
              />
            </div>
            <Button type="submit" disabled={isSaving} className="w-full h-11 text-base">
              {isSaving ? 'Salvando...' : 'Salvar Alterações'}
            </Button>
          </form>
        </CardContent>
      </Card>

      <Card className="border-border/50 shadow-subtle bg-muted/30">
        <CardHeader>
          <CardTitle>Resumo da Conta</CardTitle>
          <CardDescription>Acesse outras áreas do seu perfil.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between p-4 bg-background rounded-lg border shadow-sm">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-primary/10 text-primary rounded-full">
                <Heart className="w-5 h-5" />
              </div>
              <div>
                <p className="font-medium text-sm">Lista de Desejos</p>
                <p className="text-xs text-muted-foreground">{wishlistItems.length} itens salvos</p>
              </div>
            </div>
            <Button variant="outline" size="sm" asChild>
              <Link to="/wishlist">Ver Lista</Link>
            </Button>
          </div>

          <div className="pt-4 mt-2 border-t">
            <Button
              variant="outline"
              className="w-full justify-start text-destructive hover:text-destructive hover:bg-destructive/10 h-11 border-destructive/20"
              onClick={() => toast({ title: 'Sessão encerrada' })}
            >
              <LogOut className="w-4 h-4 mr-2" /> Encerrar Sessão
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}
