import { Link } from 'react-router-dom'
import { ChevronRight, Package, Settings, User as UserIcon, Clock } from 'lucide-react'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import useUserStore from '@/stores/useUserStore'
import { products, type Product } from '@/data/products'
import ProfileLibrary from '@/components/ProfileLibrary'
import ProfileOrders from '@/components/ProfileOrders'
import ProfileSettings from '@/components/ProfileSettings'

export default function Profile() {
  const { user, orders, library } = useUserStore()

  const libraryProducts = library
    .map((id) => products.find((p) => p.id === id))
    .filter((p): p is Product => p !== undefined)

  return (
    <div className="container mx-auto px-4 py-8 max-w-6xl">
      <nav className="flex items-center text-sm text-muted-foreground mb-8">
        <Link to="/" className="hover:text-primary transition-colors">
          Home
        </Link>
        <ChevronRight className="w-4 h-4 mx-1" />
        <span className="text-foreground font-medium">Meu Perfil</span>
      </nav>

      <div className="flex flex-col md:flex-row gap-6 md:gap-8 items-start mb-10">
        <div className="w-20 h-20 rounded-full bg-primary/10 text-primary flex items-center justify-center shrink-0">
          <UserIcon className="w-10 h-10" />
        </div>
        <div>
          <h1 className="text-3xl font-heading font-bold mb-2">Olá, {user.name.split(' ')[0]}</h1>
          <p className="text-muted-foreground text-lg">
            Bem-vindo(a) à sua central de criatividade.
          </p>
        </div>
      </div>

      <Tabs defaultValue="library" className="w-full">
        <TabsList className="grid w-full sm:w-auto grid-cols-3 mb-8 bg-muted/50 p-1 h-auto">
          <TabsTrigger value="library" className="gap-2 py-2.5">
            <Package className="w-4 h-4 hidden sm:block" /> Biblioteca
          </TabsTrigger>
          <TabsTrigger value="orders" className="gap-2 py-2.5">
            <Clock className="w-4 h-4 hidden sm:block" /> Pedidos
          </TabsTrigger>
          <TabsTrigger value="settings" className="gap-2 py-2.5">
            <Settings className="w-4 h-4 hidden sm:block" /> Conta
          </TabsTrigger>
        </TabsList>

        <TabsContent
          value="library"
          className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500"
        >
          <h2 className="text-2xl font-heading font-semibold mb-4">Minha Biblioteca de Arquivos</h2>
          <ProfileLibrary libraryProducts={libraryProducts} />
        </TabsContent>

        <TabsContent
          value="orders"
          className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500"
        >
          <h2 className="text-2xl font-heading font-semibold mb-4">Meus Pedidos</h2>
          <ProfileOrders orders={orders} />
        </TabsContent>

        <TabsContent
          value="settings"
          className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500"
        >
          <ProfileSettings />
        </TabsContent>
      </Tabs>
    </div>
  )
}
