import { Link } from 'react-router-dom'
import { Clock, CheckCircle2, Receipt } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import type { Order } from '@/stores/useUserStore'
import { useToast } from '@/hooks/use-toast'

interface ProfileOrdersProps {
  orders: Order[]
}

export default function ProfileOrders({ orders }: ProfileOrdersProps) {
  const { toast } = useToast()

  if (orders.length === 0) {
    return (
      <div className="text-center py-16 bg-muted/30 rounded-2xl border border-dashed">
        <Clock className="w-12 h-12 text-muted-foreground/30 mx-auto mb-4" />
        <h3 className="text-xl font-medium mb-2">Nenhum pedido</h3>
        <p className="text-muted-foreground mb-6">Você ainda não realizou nenhuma compra.</p>
        <Button asChild>
          <Link to="/">Começar a explorar</Link>
        </Button>
      </div>
    )
  }

  const handleDownloadReceipt = (orderId: string) => {
    toast({
      title: 'Recibo Baixado',
      description: `O recibo do pedido ${orderId} foi baixado com sucesso.`,
    })
  }

  return (
    <div className="border rounded-xl overflow-hidden bg-card shadow-subtle">
      <Table>
        <TableHeader className="bg-muted/50">
          <TableRow>
            <TableHead className="w-[120px]">Pedido</TableHead>
            <TableHead>Data</TableHead>
            <TableHead>Itens</TableHead>
            <TableHead>Status</TableHead>
            <TableHead className="text-right">Total</TableHead>
            <TableHead className="text-center w-[100px]">Ações</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {orders.map((order) => (
            <TableRow key={order.id}>
              <TableCell className="font-medium text-primary">{order.id}</TableCell>
              <TableCell>{new Date(order.date).toLocaleDateString('pt-BR')}</TableCell>
              <TableCell>
                <div className="text-sm space-y-1">
                  {order.items.map((item) => (
                    <div
                      key={item.productId}
                      className="truncate max-w-[200px] md:max-w-md text-muted-foreground"
                    >
                      {item.quantity}x {item.title}
                    </div>
                  ))}
                </div>
              </TableCell>
              <TableCell>
                <Badge
                  variant="secondary"
                  className="bg-green-100 text-green-800 hover:bg-green-100 flex items-center w-fit gap-1.5 border-none shadow-none font-medium"
                >
                  <CheckCircle2 className="w-3.5 h-3.5" /> {order.status}
                </Badge>
              </TableCell>
              <TableCell className="text-right font-bold">
                R$ {order.total.toFixed(2).replace('.', ',')}
              </TableCell>
              <TableCell className="text-center">
                <Button
                  variant="ghost"
                  size="icon"
                  title="Ver recibo"
                  onClick={() => handleDownloadReceipt(order.id)}
                >
                  <Receipt className="w-4 h-4 text-muted-foreground" />
                </Button>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}
